import React, { useState, useEffect } from 'react';
import api from '../../api';

export default function SiteSettingsPage() {
  const [settings, setSettings] = useState({
    company_name: '',
    phone_main: '',
    phone_extra: '',
    email: '',
    address: '',
    schedule: ''
  });
  
  const [gaId, setGaId] = useState('');
  
  const [loading, setLoading] = useState(true);
  const [savingSettings, setSavingSettings] = useState(false);
  const [savingGa, setSavingGa] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch Settings
        const settingsRes = await api.get('/settings/');
        setSettings({
          company_name: settingsRes.data.company_name || '',
          phone_main: settingsRes.data.phone_main || '',
          phone_extra: settingsRes.data.phone_extra || '',
          email: settingsRes.data.email || '',
          address: settingsRes.data.address || '',
          schedule: settingsRes.data.schedule || ''
        });
        setGaId(settingsRes.data.ga_tracking_id || '');

      } catch (error) {
        console.error('Failed to fetch data:', error);
        setMessage({ type: 'error', text: 'Помилка завантаження даних' });
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setSettings(prev => ({ ...prev, [name]: value }));
  };

  const handleSettingsSubmit = async (e) => {
    e.preventDefault();
    setSavingSettings(true);
    setMessage({ type: '', text: '' });

    try {
      await api.put('/settings/', {
        ...settings,
        ga_tracking_id: gaId.trim() || null
      }, {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setMessage({ type: 'success', text: 'Контактні дані успішно збережено!' });
    } catch (error) {
      console.error('Failed to save settings:', error);
      setMessage({ type: 'error', text: 'Помилка при збереженні контактів' });
    } finally {
      setSavingSettings(false);
      setTimeout(() => setMessage({ type: '', text: '' }), 5000);
    }
  };

  const handleGaSubmit = async (e) => {
    e.preventDefault();
    setSavingGa(true);
    setMessage({ type: '', text: '' });

    try {
      await api.put('/settings/', {
          ...settings,
          ga_tracking_id: gaId.trim() || null
      }, {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setMessage({ type: 'success', text: 'Google Analytics ID збережено!' });
    } catch {
      setMessage({ type: 'error', text: 'Помилка збереження GA ID' });
    } finally {
      setSavingGa(false);
      setTimeout(() => setMessage({ type: '', text: '' }), 5000);
    }
  };


  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
      
      {message.text && (
        <div className={`p-4 justify-between flex items-center rounded-lg text-sm ${
          message.type === 'success' ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
        }`}>
          <span>{message.text}</span>
        </div>
      )}

      {/* ─── CONTACT SETTINGS ────────────────────────────────────── */}
      <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="border-b border-gray-100 bg-gray-50/50 p-6">
          <h2 className="text-2xl font-bold font-montserrat text-gray-900">
            Контакти та Інформація Сайту
          </h2>
          <p className="mt-1 text-sm text-gray-500">
            Оновіть контактну інформацію, яка відображатиметься в шапці (Header) та підвалі (Footer).
          </p>
        </div>

        <form onSubmit={handleSettingsSubmit} className="p-6 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="col-span-1 md:col-span-2">
              <label htmlFor="company_name" className="block text-sm font-medium text-gray-700">Назва Компанії</label>
              <input type="text" id="company_name" name="company_name" value={settings.company_name} onChange={handleChange} className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm p-2 border" required />
            </div>

            <div>
              <label htmlFor="phone_main" className="block text-sm font-medium text-gray-700">Головний Телефон (з шапки)</label>
              <input type="text" id="phone_main" name="phone_main" value={settings.phone_main} onChange={handleChange} placeholder="+380 (99) 123-45-67" className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm p-2 border" />
            </div>

            <div>
              <label htmlFor="phone_extra" className="block text-sm font-medium text-gray-700">Додатковий Телефон (для підвалу)</label>
              <input type="text" id="phone_extra" name="phone_extra" value={settings.phone_extra} onChange={handleChange} placeholder="+380 (98) 765-43-21" className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm p-2 border" />
            </div>

            <div>
              <label htmlFor="email" className="block text-sm font-medium text-gray-700">Email</label>
              <input type="email" id="email" name="email" value={settings.email} onChange={handleChange} className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm p-2 border" />
            </div>

            <div className="col-span-1 md:col-span-2">
              <label htmlFor="address" className="block text-sm font-medium text-gray-700">Фізична Адреса</label>
              <input type="text" id="address" name="address" value={settings.address} onChange={handleChange} placeholder="Київ та Київська область" className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm p-2 border" />
            </div>

            <div className="col-span-1 md:col-span-2">
              <label htmlFor="schedule" className="block text-sm font-medium text-gray-700">Графік Роботи</label>
              <textarea id="schedule" name="schedule" rows={3} value={settings.schedule} onChange={handleChange} placeholder="Пн-Нд: 08:00 - 20:00" className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm font-mono p-2 border" />
            </div>
          </div>

          <div className="border-t border-gray-100 pt-5 flex justify-end">
            <button type="submit" disabled={savingSettings} className={`inline-flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white ${savingSettings ? 'bg-orange-400' : 'bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500'}`}>
              {savingSettings ? 'Збереження...' : 'Зберегти Контакти'}
            </button>
          </div>
        </form>
      </div>

      {/* ─── GOOGLE ANALYTICS SETTINGS ───────────────────────────── */}
      <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
        <div className="border-b border-gray-100 bg-gray-50/50 p-6">
          <h2 className="text-2xl font-bold font-montserrat text-gray-900">
            📊 Google Analytics
          </h2>
          <p className="mt-1 text-sm text-gray-500">
            Вставте код відстеження Google Analytics. Він буде працювати на всіх сторінках сайту.
          </p>
        </div>

        <form onSubmit={handleGaSubmit} className="p-6 space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Tracking ID (Measurement ID)</label>
            <input type="text" value={gaId} onChange={(e) => setGaId(e.target.value)} placeholder="G-XXXXXXXXXX" className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-orange-500 focus:border-orange-500 sm:text-sm font-mono p-2 border" />
            <p className="mt-2 text-xs text-gray-500">Знайдіть його в Google Analytics → Адмін → Потоки даних → Ідентифікатор</p>
          </div>

          <div className="bg-yellow-50 rounded-lg p-4 text-sm text-yellow-800 border border-yellow-200">
            <strong>💡 Підказка:</strong> Вставте тільки Measurement ID (наприклад <code className="bg-yellow-100 px-1 rounded">G-ABC123XYZ</code>).
          </div>

          <div className="border-t border-gray-100 pt-5 flex justify-end">
             <button type="submit" disabled={savingGa} className={`inline-flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white ${savingGa ? 'bg-orange-400' : 'bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500'}`}>
              {savingGa ? 'Збереження...' : 'Зберегти Аналітику'}
            </button>
          </div>
        </form>
      </div>

    </div>
  );
}
